// ── CITY PAIRS for /tracking/[origin]-to-[destination] pages ──
export const cityPairs = allUSCities.slice(0, 30).flatMap((origin) =>
  allUSCities
    .filter((dest) => dest.slug !== origin.slug && dest.stateCode !== origin.stateCode)
    .slice(0, 8)
    .map((dest) => ({
      originSlug: origin.slug,
      destSlug: dest.slug,
      originCity: origin.city,
      destCity: dest.city,
      originState: origin.stateCode,
      destState: dest.stateCode,
      slug: `${origin.slug}-to-${dest.slug}`,
    }))
);

export default allUSCities;
